/** SSOT labels — common/rule/account-normal-balance.md */

export const ACCOUNT_TYPE_OPTIONS = [
  { value: 'Asset', label: 'Tài sản' },
  { value: 'Liability', label: 'Nợ phải trả' },
  { value: 'Equity', label: 'Vốn chủ sở hữu' },
  { value: 'Revenue', label: 'Doanh thu' },
  { value: 'Expense', label: 'Chi phí' },
] as const;

export const NORMAL_BALANCE_OPTIONS = [
  { value: 'Debit', label: 'Dư Nợ (tăng Nợ · giảm Có)' },
  { value: 'Credit', label: 'Dư Có (tăng Có · giảm Nợ)' },
] as const;

const ACCOUNT_TYPE_LABEL: Record<string, string> = Object.fromEntries(
  ACCOUNT_TYPE_OPTIONS.map(o => [o.value, o.label]),
);

const NORMAL_BALANCE_LABEL: Record<string, string> = Object.fromEntries(
  NORMAL_BALANCE_OPTIONS.map(o => [o.value, o.label]),
);

export function formatAccountTypeLabel(value?: string | null): string {
  if (!value?.trim()) return '—';
  return ACCOUNT_TYPE_LABEL[value] ?? value;
}

export function formatNormalBalanceLabel(value?: string | null): string {
  if (!value?.trim()) return '—';
  return NORMAL_BALANCE_LABEL[value] ?? value;
}

/** Infer TT200 defaults when user types account code (create form). */
export function inferAccountNatureFromCode(code: string): {
  accountType?: string;
  normalBalance?: string;
} {
  const trimmed = code.trim();
  if (!trimmed) return {};

  if (trimmed.startsWith('214')) {
    return { accountType: 'Asset', normalBalance: 'Credit' };
  }
  if (trimmed.startsWith('521')) {
    return { accountType: 'Revenue', normalBalance: 'Debit' };
  }

  const first = trimmed[0];
  switch (first) {
    case '1':
    case '2':
      return { accountType: 'Asset', normalBalance: 'Debit' };
    case '3':
      return { accountType: 'Liability', normalBalance: 'Credit' };
    case '4':
      return { accountType: 'Equity', normalBalance: 'Credit' };
    case '5':
      return { accountType: 'Revenue', normalBalance: 'Credit' };
    case '6':
    case '8':
      return { accountType: 'Expense', normalBalance: 'Debit' };
    case '7':
      return { accountType: 'Revenue', normalBalance: 'Credit' };
    default:
      return { normalBalance: 'Debit' };
  }
}
